const e=JSON.parse('{"key":"v-0d78b1f0","path":"/%E5%89%8D%E7%AB%AF/vue/pinia.html","title":"pinia","lang":"zh-CN","frontmatter":{"title":"pinia","icon":"vue","date":"2023-07-19T00:00:00.000Z","category":["前端","vue"],"tag":["前端","pinia","vue2"],"star":true,"description":"Pinia Pinia 是什么？ Pinia 是 Vue 的专属状态管理库，它允许你跨组件或页面共享状态。如果你熟悉组合式 API 的话，你可能会认为可以通过一行简单的 export const state = reactive({}) 来共享一个全局状态。对于单页应用来说确实可以，但如果应用在服务器端渲染，这可能会使你的应用暴露出一些安全漏洞。 而如果使用 Pinia，即使在小型单页应用中，你也可以获得如下功能： Devtools 支持 追踪 actions、mutations 的时间线 在组件中展示它们所用到的 Store 让调试更容易的 Time travel 热更新 不必重载页面即可修改 Store 开发时可保持当前的 State 插件：可通过插件扩展 Pinia 功能 为 JS 开发者提供适当的 TypeScript 支持以及自动补全功能。 支持服务端渲染","head":[["meta",{"property":"og:url","content":"https://skym1.gitee.io/%E5%89%8D%E7%AB%AF/vue/pinia.html"}],["meta",{"property":"og:site_name","content":"Skyme的博客"}],["meta",{"property":"og:title","content":"pinia"}],["meta",{"property":"og:description","content":"Pinia Pinia 是什么？ Pinia 是 Vue 的专属状态管理库，它允许你跨组件或页面共享状态。如果你熟悉组合式 API 的话，你可能会认为可以通过一行简单的 export const state = reactive({}) 来共享一个全局状态。对于单页应用来说确实可以，但如果应用在服务器端渲染，这可能会使你的应用暴露出一些安全漏洞。 而如果使用 Pinia，即使在小型单页应用中，你也可以获得如下功能： Devtools 支持 追踪 actions、mutations 的时间线 在组件中展示它们所用到的 Store 让调试更容易的 Time travel 热更新 不必重载页面即可修改 Store 开发时可保持当前的 State 插件：可通过插件扩展 Pinia 功能 为 JS 开发者提供适当的 TypeScript 支持以及自动补全功能。 支持服务端渲染"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-08-28T01:15:29.000Z"}],["meta",{"property":"article:author","content":"Skyme"}],["meta",{"property":"article:tag","content":"前端"}],["meta",{"property":"article:tag","content":"pinia"}],["meta",{"property":"article:tag","content":"vue2"}],["meta",{"property":"article:published_time","content":"2023-07-19T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-08-28T01:15:29.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"pinia\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-07-19T00:00:00.000Z\\",\\"dateModified\\":\\"2023-08-28T01:15:29.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Skyme\\",\\"url\\":\\"https://skym1.gitee.io\\"}]}"]]},"headers":[{"level":2,"title":"Pinia 是什么？","slug":"pinia-是什么","link":"#pinia-是什么","children":[{"level":3,"title":"Store是什么？","slug":"store是什么","link":"#store是什么","children":[]},{"level":3,"title":"应该使用的地方","slug":"应该使用的地方","link":"#应该使用的地方","children":[]}]},{"level":2,"title":"定义Store","slug":"定义store","link":"#定义store","children":[{"level":3,"title":"关于如何解决vue2报错","slug":"关于如何解决vue2报错","link":"#关于如何解决vue2报错","children":[]}]}],"git":{"createdTime":1693185329000,"updatedTime":1693185329000,"contributors":[{"name":"Skym1","email":"412399240@qq.com","commits":1}]},"readingTime":{"minutes":2.31,"words":694},"filePathRelative":"前端/vue/pinia.md","localizedDate":"2023年7月19日","excerpt":"<h1> Pinia</h1>\\n<h2> Pinia 是什么？</h2>\\n<hr>\\n<p>Pinia 是 Vue 的专属状态管理库，它允许你跨组件或页面共享状态。如果你熟悉组合式 API 的话，你可能会认为可以通过一行简单的 <code>export const state = reactive({})</code> 来共享一个全局状态。对于单页应用来说确实可以，但如果应用在服务器端渲染，这可能会使你的应用暴露出一些安全漏洞。 而如果使用 Pinia，即使在小型单页应用中，你也可以获得如下功能：</p>\\n<ul>\\n<li>Devtools 支持\\n<ul>\\n<li>追踪 actions、mutations 的时间线</li>\\n<li>在组件中展示它们所用到的 Store</li>\\n<li>让调试更容易的 Time travel</li>\\n</ul>\\n</li>\\n<li>热更新\\n<ul>\\n<li>不必重载页面即可修改 Store</li>\\n<li>开发时可保持当前的 State</li>\\n</ul>\\n</li>\\n<li>插件：可通过插件扩展 Pinia 功能</li>\\n<li>为 JS 开发者提供适当的 TypeScript 支持以及<strong>自动补全</strong>功能。</li>\\n<li>支持服务端渲染</li>\\n</ul>","autoDesc":true}');export{e as data};
